/// <summary>
/// Extension of the <c>NumberSeqModulePurchaseOrder</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(Classstr(NumberSeqModulePurchaseOrder))]
final class NumberSeqModulePurchaseOrderETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Loads the information for the new number sequence.
/// </summary>
protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();

    next loadModule();

    datatype.parmDatatypeId(extendedTypeNum(ETGSPAINPurchOperationId));
    datatype.parmReferenceHelp(literalStr("@ETGSPAINLabels:ETGSPAINPurchOperationId"));
    datatype.parmReferenceLabel(literalStr("@ETGSPAINLabels:ETGSPAINPurchOperationId"));        
    datatype.parmWizardIsContinuous(false);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardIsChangeDownAllowed(NoYes::No);
    datatype.parmWizardIsChangeUpAllowed(NoYes::No);
    datatype.parmWizardHighest(999999999);
    datatype.parmSortField(30);  

    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);
    this.create(datatype);
}

/// <summary>
/// Returns the number sequence reference of EDT.
/// </summary>
/// <returns>
/// Returns a <c>numberSequenceReference</c>.
/// </returns>
static numberSequenceReference ETGSPAINnumRefOperationId()
{
    return NumberSeqReference::findReference(extendedTypeNum(ETGSPAINPurchOperationId));
}
